1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5G premium for empty items list (processing fee only)", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      });
11	      expect(result.results[0]).toEqual({ premium: 5 });
12	    });
13	    it("computes premium for a single sword (100G base + 5G fee = 105G)", () => {
14	      const result = processScenario({
15	        customer: { yearsWithMHPCO: 0 },
16	        steps: [
17	          {
18	            op: "quote" as const,
19	            items: [
20	              { type: "sword", material: "steel", enchantment: 0, cursed: false },
21	            ],
22	          },
23	        ],
24	      });
25	      expect(result.results[0]).toEqual({ premium: 105 });
26	    });
27	    it("computes premium for a single amulet (60G base + 5G fee = 65G)", () => {
28	      const result = processScenario({
29	        customer: { yearsWithMHPCO: 0 },
30	        steps: [
31	          {
32	            op: "quote" as const,
33	            items: [
34	              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
35	            ],
36	          },
37	        ],
38	      });
39	      expect(result.results[0]).toEqual({ premium: 65 });
40	    });
41	    it.todo("computes premium for multiple items (sword + amulet = 160G base + 5G fee)");
42	  });
43	
44	  describe("Quote - component premiums", () => {
45	    it.todo("computes premium for 2 runes (50G base + 5G fee)");
46	    it.todo("computes premium for a block of 3 alike components (60G base + 5G fee)");
47	    it.todo("computes premium for 4 runes (100G base, no block + 5G fee)");
48	    it.todo("computes premium for mixed components, no block (2 runes + 1 moonstone = 75G base + 5G fee)");
49	    it.todo("computes premium for two separate blocks (3 runes + 3 moonstones = 120G base + 5G fee)");
50	  });
51	
52	  describe("Quote - item-specific modifiers", () => {
53	    it.todo("adds 50% cursed surcharge to a cursed item's base premium");
54	    it.todo("adds 30% high-enchantment surcharge for enchantment >= 5");
55	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
56	    it.todo("applies cursed surcharge only to the cursed item in a multi-item policy");
57	  });
58	
59	  describe("Quote - policy-wide modifiers", () => {
60	    it.todo("adds 10% first insurance surcharge (applied to every quote)");
61	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
62	    it.todo("applies 15% follow-up discount on second and subsequent quotes");
63	    it.todo("combines loyalty, first insurance, and follow-up modifiers");
64	  });
65	
66	  describe("Quote - rounding", () => {
67	    it.todo("rounds premium up in MHPCO's favor");
68	  });
69	
70	  describe("Quote - errors", () => {
71	    it.todo("throws error for unknown item type");
72	  });
73	
74	  describe("Claim - basic payout", () => {
75	    it.todo("applies 100G deductible per damaged item");
76	    it.todo("applies deductible to each item independently in multi-item damage");
77	  });
78	
79	  describe("Claim - reimbursement rules", () => {
80	    it.todo("reimburses at 50% for items with enchantment >= 8");
81	    it.todo("fully reimburses damage to dragon-material items");
82	    it.todo("applies 50% rule when item has both enchantment >= 8 and dragon material");
83	    it.todo("fully reimburses dragon-material item with enchantment < 8");
84	  });
85	
86	  describe("Claim - cap", () => {
87	    it.todo("caps total payout at 2x insurance sum");
88	    it.todo("tracks remaining cap across successive claims");
89	  });
90	
91	  describe("Claim - rounding", () => {
92	    it.todo("rounds payout down in MHPCO's favor");
93	  });
94	
95	  describe("Claim - errors", () => {
96	    it.todo("throws error when damage references item not in policy");
97	    it.todo("throws error for negative damage amount");
98	    it.todo("throws error when more damages of a type than items insured");
99	  });
100	
101	  describe("Integration", () => {
102	    it.todo("newcomer with cursed sword: premium 165G");
103	    it.todo("long-standing customer second contract with cursed enchanted sword: premium 160G");
104	  });
105	});
