1	const PROCESSING_FEE = 5;
2	
3	const basePremium = (item: any): number => {
4	  if (item.type === "sword") return 100;
5	  if (item.type === "amulet") return 60;
6	  return 0;
7	};
8	
9	export const processScenario = (scenario: any): any => {
10	  const results = scenario.steps.map((step: any) => {
11	    const itemsTotal = step.items.reduce(
12	      (sum: number, item: any) => sum + basePremium(item),
13	      0,
14	    );
15	    const premium = PROCESSING_FEE + itemsTotal;
16	    return { premium };
17	  });
18	  return { results };
